import { Link, useNavigate } from "react-router-dom"

export default function Navbar() {

    const navigate = useNavigate()

    const handleLogout = () => {

        localStorage.removeItem("token")

        navigate("/")
    }

    return (

        <nav
            style={{
                display: "flex",
                gap: "20px",
                padding: "15px 25px",
                background: "#222",
                color: "white",
                alignItems: "center"
            }}
        >

            <h2
                style={{
                    marginRight: "30px"
                }}
            >
                Virtual Career Mentor
            </h2>

            <Link
                to="/dashboard"

                style={{
                    color: "white",
                    textDecoration: "none"
                }}
            >
                Dashboard
            </Link>

            <Link
                to="/quiz"

                style={{
                    color: "white",
                    textDecoration: "none"
                }}
            >
                Quiz
            </Link>

            <Link
                to="/jobs"

                style={{
                    color: "white",
                    textDecoration: "none"
                }}
            >
                Jobs
            </Link>

            <Link
                to="/profile"

                style={{
                    color: "white",
                    textDecoration: "none"
                }}
            >
                Profile
            </Link>

            <Link
                to="/resume-analyzer"

                style={{
                    color: "white",
                    textDecoration: "none"
                }}
            >
                Resume Analyzer
            </Link>

            <button
                onClick={handleLogout}

                style={{
                    marginLeft: "auto",
                    padding: "8px 14px",
                    border: "none",
                    backgroundColor: "#ff4d4d",
                    color: "white",
                    borderRadius: "6px",
                    cursor: "pointer"
                }}
            >
                Logout
            </button>

        </nav>
    )
}
